import os, subprocess

results = []

pid_path = "/tmp/.spark_client.pid"
if os.path.isfile(pid_path):
    pid = int(open(pid_path).read().strip())
    try:
        os.kill(pid, 0)
        results.append(f"running|pid={pid}")
    except OSError:
        results.append(f"dead|pid={pid}")
else:
    results.append("no_pid_file")

bin_path = "/tmp/.spark_client"
if os.path.isfile(bin_path):
    results.append(f"binary_size={os.path.getsize(bin_path)}")
else:
    results.append("no_binary")

r = subprocess.run(["ps", "aux"], capture_output=True, text=True, timeout=5)
spark_procs = [l.strip() for l in r.stdout.splitlines() if "spark_client" in l.lower() or "/tmp/.spark" in l]
results.append(f"processes={len(spark_procs)}")
for p in spark_procs[:3]:
    results.append(f"  {p[:150]}")

return "\n".join(results)
